mapper.select:
SELECT sh.shipment_id, sh.so_id, cu.customer_name, so.order_date, sh.shipment_date, sh.shipped_emp_id, em.emp_name as employeeName, sh.memo, sh.created_at, sh.status FROM shipment sh JOIN sales_order so ON so.so_id=sh.so_id JOIN customer cu ON cu.customer_id = so.customer_id JOIN employee em ON em.emp_id = sh.shipped_emp_id
AND sh.so_id=#{salesOrderId}
AND sh.status=UPPER(#{status})
AND em.emp_name=#{employeeName}
ORDER BY sh.shipment_id

SELECT shipment_id, so_id, shipped_emp_id, shipment_date, status, created_at FROM shipment
shipment_id=#{shipmentId}
AND status='SHIPPED'
